                    <div key={block} style={{ background: 'var(--bg-secondary)', padding: '20px', borderRadius: '15px', boxShadow: '0 10px 30px rgba(0,0,0,0.3)', minWidth: '220px', borderTop: '4px solid var(--accent-cyan)', position: 'relative', overflow: 'hidden' }}>
